## 17.12 Direct multi-horizon forecasting

A direct strategy trains one model per horizon. For $H=14$, we train

$$
\widehat f_1,\widehat f_2,\ldots,\widehat f_{14}.
$$

Each model uses the same origin-time features but a different target.

::: {.cell execution_count=6}
``` {.python .cell-code}
H = 14
base = series.copy()

# Origin-time features with no horizon-specific target yet.
features_base = make_lagged_features(base, max_lag=14, rolling_windows=(7, 28), horizon=1)
feature_cols_direct = [c for c in features_base.columns if c.startswith(("lag_", "roll_", "sin_", "cos_"))]
feature_cols_direct += ["day_of_week", "is_weekend"]

# Add targets for all horizons.
for h in range(1, H + 1):
    features_base[f"target_h{h}"] = series["y"].shift(-h).reindex(features_base.index).values
features_base = features_base.dropna().reset_index(drop=True)

origin_date = features_base["ds"].iloc[int(0.80 * len(features_base))]
train_direct = features_base[features_base["ds"] < origin_date]
origin_row = features_base[features_base["ds"] == origin_date].iloc[[0]]

direct_forecast = []
for h in range(1, H + 1):
    model = Pipeline([
        ("prep", preprocess_tree),
        ("model", GradientBoostingRegressor(
            n_estimators=80,
            learning_rate=0.05,
            max_depth=3,
            random_state=7339 + h,
        )),
    ])
    model.fit(train_direct[feature_cols], train_direct[f"target_h{h}"])
    direct_forecast.append(model.predict(origin_row[feature_cols])[0])

origin_idx = series.index[series["ds"] == origin_date][0]
actual_path = series.loc[origin_idx + 1: origin_idx + H, "y"].values
future_dates = series.loc[origin_idx + 1: origin_idx + H, "ds"].values

plt.figure(figsize=(8, 3.5))
plt.plot(series.loc[origin_idx-80:origin_idx, "ds"], series.loc[origin_idx-80:origin_idx, "y"], label="history")
plt.plot(future_dates, actual_path, marker="o", label="actual")
plt.plot(future_dates, direct_forecast, marker="o", label="direct ML forecast")
plt.xlabel("date")
plt.ylabel("value")
plt.title("Direct multi-horizon forecast")
plt.legend()
plt.tight_layout()
plt.show()
